// frontend/src/pages/LoginPage.js
import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    try {
      const user = await login(email, password);
      navigate(user.role === 'admin' ? '/admin' : '/home');
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed. Please try again.');
    }
  };

  // Reusable style objects
  const styles = {
    page: {
      backgroundColor: '#FAE8ED',
      minHeight: '100vh',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      fontFamily: 'Georgia, serif',
      color: 'rgb(12, 75, 52)',
      padding: '20px',
    },
    container: {
      backgroundColor: '#f7c6d9',
      padding: '40px',
      borderRadius: '20px',
      boxShadow: '0 10px 30px rgba(0,0,0,0.1)',
      maxWidth: '400px',
      width: '100%',
      textAlign: 'center',
    },
    heading: {
      fontSize: '36px',
      fontWeight: 'bold',
      marginBottom: '25px',
    },
    form: {
      display: 'flex',
      flexDirection: 'column',
      gap: '18px',
    },
    input: {
      padding: '14px 20px',
      borderRadius: '50px',
      border: '2px solid transparent',
      fontSize: '16px',
      outline: 'none',
      transition: 'all 0.3s ease',
      backgroundColor: '#f7c6d9',
      color: 'rgb(12, 75, 52)',
    },
    inputFocus: {
      backgroundColor: '#ffffff',
      borderColor: 'rgb(12, 75, 52)',
      boxShadow: '0 8px 20px rgba(12, 75, 52, 0.1)',
    },
    button: {
      padding: '16px 40px',
      borderRadius: '50px',
      border: 'none',
      fontWeight: 'bold',
      fontSize: '16px',
      cursor: 'pointer',
      backgroundColor: 'rgb(12, 75, 52)',
      color: '#f7c6d9',
      transition: 'all 0.3s ease',
      boxShadow: '0 4px 15px rgba(12, 75, 52, 0.2)',
    },
    buttonHover: {
      backgroundColor: 'rgb(241, 125, 194)',
      color: '#fff',
      transform: 'scale(1.05)',
    },
    error: {
      color: '#ff4d4d',
      fontSize: '0.9rem',
      marginBottom: '10px',
      fontWeight: '500',
    },
    link: {
      color: 'rgb(12, 75, 52)',
      fontWeight: 'bold',
      textDecoration: 'none',
      transition: 'all 0.3s ease',
    },
    linkHover: {
      color: 'rgb(241, 125, 194)',
    },
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>Login to TheFolio</h2>
        {error && <p style={styles.error}>{error}</p>}

        <form style={styles.form} onSubmit={handleSubmit}>
          <input
            type="email"
            placeholder="Email address"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
            style={styles.input}
            onFocus={(e) => (e.target.style = { ...styles.input, ...styles.inputFocus })}
            onBlur={(e) => (e.target.style = { ...styles.input })}
          />

          <input
            type="password"
            placeholder="Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
            style={styles.input}
            onFocus={(e) => (e.target.style = { ...styles.input, ...styles.inputFocus })}
            onBlur={(e) => (e.target.style = { ...styles.input })}
          />

          <button
            type="submit"
            style={styles.button}
            onMouseEnter={(e) => (e.target.style = { ...styles.button, ...styles.buttonHover })}
            onMouseLeave={(e) => (e.target.style = { ...styles.button })}
          >
            Login
          </button>
        </form>

        <p style={{ marginTop: '20px' }}>
          Don't have an account?{' '}
          <Link
            to="/register"
            style={styles.link}
            onMouseEnter={(e) => (e.target.style = { ...styles.link, ...styles.linkHover })}
            onMouseLeave={(e) => (e.target.style = { ...styles.link })}
          >
            Register here
          </Link>
        </p>
      </div>
    </div>
  );
};

export default LoginPage;
